sql:
SELECT adj_close_average
FROM weekly_trends
WHERE stock_id = 1 AND date = '2018-01-21';

SELECT stock_id, AVG(close_average) AS avg_close_price
FROM daily_trends
GROUP BY stock_id;

SELECT open_average, close_average
FROM daily_trends
WHERE stock_id = 1 AND date = '2018-01-14';

SELECT ROUND(volume_average, 2) AS average_volume
FROM daily_trends
WHERE stock_id = 0 AND date = '2018-01-14';

SELECT AVG(close_price) AS average_close_price
FROM stock_prices
WHERE date = '2018-01-14';

SELECT exchange_name, trading_hours
FROM stock_exchanges
WHERE trading_hours = (SELECT MAX(trading_hours) FROM stock_exchanges);
